import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-download.IKA_571t.js";const a=JSON.parse(`{"title":"Impostare IntelliJ IDEA","description":"Una guida passo per passo su come impostare IntelliJ IDEA per creare mod usando Fabric.","frontmatter":{"title":"Impostare IntelliJ IDEA","description":"Una guida passo per passo su come impostare IntelliJ IDEA per creare mod usando Fabric.","authors":["2xsaiko","Andrew6rant","asiekierka","Daomephsta","dicedpixels","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","TelepathicGrunt"],"authors-nogithub":["siglong"],"prev":{"text":"Impostare il Tuo IDE","link":"../setting-up"},"next":{"text":"Aprire un progetto in IntelliJ IDEA","link":"./opening-a-project"},"resources":{"https://www.jetbrains.com/idea/download/":"Scarica IntelliJ IDEA da JetBrains","https://www.jetbrains.com/help/idea/getting-started.html":"Come iniziare con IntelliJ IDEA (EN)","https://plugins.jetbrains.com/plugin/8327-minecraft-development":"Plugin Minecraft Development - JB Marketplace"},"files":[]},"headers":[],"relativePath":"it_it/develop/getting-started/intellij-idea/setting-up.md","filePath":"translated/it_it/develop/getting-started/intellij-idea/setting-up.md","lastUpdated":1774518827000}`);var o={name:`it_it/develop/getting-started/intellij-idea/setting-up.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Impostare IntelliJ IDEA <a class="header-anchor" href="#h1" aria-label="Permalink to “Impostare IntelliJ IDEA”">​</a></h1><div class="info custom-block"><p class="custom-block-title">PREREQUISITI</p><p>Assicurati di aver già <a href="./../setting-up#install-jdk-21">installato un JDK</a>.</p></div><h2 id="installing-intellij-idea" tabindex="-1">Installare IntelliJ IDEA <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “Installare IntelliJ IDEA”">​</a></h2><p>Se non hai IntelliJ IDEA installato, puoi scaricarlo dal <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">sito ufficiale</a> - segui i passaggi per l&#39;installazione sul tuo sistema operativo.</p><p><img src="/assets/develop/getting-started/idea-download.png" alt="Prompt per scaricare IntelliJ IDEA" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">Installare il plugin &quot;Minecraft Development&quot; <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “Installare il plugin &quot;Minecraft Development&quot;”">​</a></h2><p>Il plugin Minecraft Development fornisce supporto per il modding con Fabric, ed è il plugin più importante da installare.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Anche se questo plugin non è strettamente necessario, esso rende il modding con Fabric molto più semplice - dovresti installarlo.</p></div><p>Puoi installarlo aprendo IntelliJ IDEA, e poi navigando a <strong>File</strong> &gt; <strong>Impostazioni</strong> &gt; <strong>Plugin</strong> &gt; Scheda <strong>Marketplace</strong>, poi inserisci <code>Minecraft Development</code> nella barra di ricerca, e clicca il pulsante <strong>Installa</strong>.</p><p>In alternativa, puoi scaricarlo dalla <a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">pagina del plugin</a> e poi installarlo navigando a <strong>File</strong> &gt; <strong>Impostazioni</strong> &gt; <strong>Plugin</strong> &gt; <strong>Installa Plugin dal Disco</strong>.</p><h3 id="about-creating-a-project" tabindex="-1">Riguardo alla creazione di un progetto <a class="header-anchor" href="#about-creating-a-project" aria-label="Permalink to “Riguardo alla creazione di un progetto”">​</a></h3><p>È vero che quel plugin permette di creare un progetto, ma questo non è consigliato perché i modelli che usa sono spesso obsoleti. Consigliamo invece di seguire la pagina <a href="./../creating-a-project">Creare un progetto</a> per usare il generatore di mod modello di Fabric.</p>`,12)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};